```python
def process_user_data(users):
    processed_results = []
    for user in users:
        if user is not None:
            if 'id' in user:
                if user['id'] > 0:
                    if user.get('status') == 'active':
                        if 'email' in user:
                            if '@' in user['email']:
                                email = user['email'].lower()
                                if user.get('role') == 'admin':
                                    processed_results.append({'id': user['id'], 'email': email, 'access': 'high'})
                                elif user.get('role') == 'editor':
                                    processed_results.append({'id': user['id'], 'email': email, 'access': 'med'})
                                else:
                                    processed_results.append({'id': user['id'], 'email': email, 'access': 'low'})
                            else:
                                processed_results.append({'id': user['id'], 'email': 'invalid', 'access': 'none'})
                        else:
                            processed_results.append({'id': user['id'], 'email': 'no_email', 'access': 'none'})
                    else:
                        continue
                else:
                    continue
            else:
                continue
        else:
            continue
    return processed_results
```

