def process_user_data(users):
    processed_results = []
    for user in users:
        if user is None or 'id' not in user or user['id'] <= 0:
            continue
        if user.get('status') != 'active':
            continue

        email = user.get('email')
        if email is None or '@' not in email:
            processed_results.append({'id': user['id'], 'email': 'no_email' if email is None else 'invalid', 'access': 'none'})
            continue

        email_lower = email.lower()
        access_level = 'low'
        if user.get('role') == 'admin':
            access_level = 'high'
        elif user.get('role') == 'editor':
            access_level = 'med'

        processed_results.append({'id': user['id'], 'email': email_lower, 'access': access_level})
    return processed_results
```

